import{_ as e,o as a,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"32. Superannuation","description":"","frontmatter":{"title":"32. Superannuation","eba":"Medical Specialists 2022-2026","topics":["wages","superannuation","preliminary","definitions"]},"headers":[],"relativePath":"ebas/medical-specialists/wages/32-superannuation.md","filePath":"ebas/medical-specialists/wages/32-superannuation.md"}'),r={name:"ebas/medical-specialists/wages/32-superannuation.md"};function i(s,n,p,u,d,l){return a(),t("div",null,[...n[0]||(n[0]=[o('<h1 id="_32-superannuation" tabindex="-1">32. Superannuation <a class="header-anchor" href="#_32-superannuation" aria-label="Permalink to &quot;32. Superannuation&quot;">​</a></h1><p>The subject of superannuation contributions is dealt with extensively by federal legislation which prescribes the obligations and entitlements regarding superannuation. This clause is ancillary to and supplements those provisions.</p><p><strong>32.1</strong> Definitions</p><p>In this clause:</p><p><strong>(a)</strong> default fund means the Aware Super superannuation fund (or its successor) while it provides a &quot;MySuper product&quot; as defined by the Act; and</p><p><strong>(b)</strong> preferred superannuation fund means a fund that meets the definition of a superannuation fund in the Superannuation Guarantee (Administration) Act 1992 (Cth).</p><p><strong>32.2</strong> Existing Doctors</p><p>Doctors will have the choice to nominate that the Employer contributions and their own contributions are made to the Doctor’s preferred superannuation fund (as defined above).</p><p><strong>32.3</strong> New Doctors</p><p>The Employer will offer to make superannuation contributions on behalf of a Doctor to:</p><p><strong>(a)</strong> the Doctor’s preferred superannuation fund; or</p><p><strong>(b)</strong> Aware Super superannuation funds (or successor).</p><p><strong>32.4</strong> Where new Doctors do not nominate fund</p><p>If the Doctor does not nominate a fund, the Employer will pay the Doctor’s superannuation contributions to the default fund.</p><p><strong>32.5</strong> Calculation of superannuation contributions</p><p>Superannuation contributions paid by the Employer will be calculated and paid on:</p><p><strong>(a)</strong> ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Doctor’s pre-salary packaging earnings;</p><p><strong>(b)</strong> any additional amounts consistent with the trust deed of the superannuation fund; and</p><p><strong>(c)</strong> any payment for a period of paid parental leave under subclause 54.5.</p><p><strong>32.6</strong> Superannuation during parental leave – from 11 April 2022</p><p>From 11 April 2022, the Employer will make superannuation contributions throughout any period of parental leave, paid or unpaid. Such contributions will be calculated as follows:</p><p><strong>(e)</strong> The Doctor’s ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Doctors&#39;s pre- salary packaging earnings and any additional amounts consistent with the trust deed of the superannuation fund over 26 full pay periods immediately prior to commencing parental leave and divided by 52 (Weekly Parental Leave Super Contribution) any additional amounts consistent with the trust deed of the superannuation fund; and</p><p><strong>(f)</strong> The Weekly Parental Leave Super Contribution will be paid during each week of Parental Leave (both paid and unpaid) save that:</p><p><strong>(i)</strong> The Doctor will receive a pro-rata payment for a period less than one (1) week; and</p><p><strong>(ii)</strong> where, during the period of parental leave (either paid or unpaid), the Doctor’s rate of pay increases under subclause 31.1, the Doctor’s pre-salary packaging earnings as calculated above will be increased accordingly from the relevant date and superannuation paid on the increased amount.</p><p>Plain language terms: super, SG.</p>',26)])])}const g=e(r,[["render",i]]);export{h as __pageData,g as default};
